// ================================================
//  EDIT THIS NODE -- all your settings live here
// ================================================

const BRAND_NAME       = 'Your Brand Name';
const NICHE            = 'AI automation for business owners';
const TARGET_AUDIENCE  = 'Solo founders and agency owners interested in AI tools';
const TONE_OF_VOICE    = 'Direct, confident, no fluff -- like a smart friend who knows their stuff';
const ELEVENLABS_VOICE_ID   = 'YOUR_ELEVENLABS_VOICE_ID';
const CREATOMATE_TEMPLATE_ID = 'YOUR_CREATOMATE_TEMPLATE_ID';
const DRIVE_FOLDER_NAME      = 'AI Videos';
const VIDEO_DURATION_SECONDS = 50;

// ================================================
//  DO NOT EDIT BELOW THIS LINE
// ================================================

const form = $input.first().json;
const topic    = form['Video Topic or Idea'] || '';
const platform = form['Target Platform'] || 'All Platforms';
const notes    = form['Additional Keywords or Notes'] || '';
const timestamp = new Date().toISOString();
const videoId   = 'VID-' + Date.now();

return [{
  json: {
    brand_name:           BRAND_NAME,
    niche:                NICHE,
    target_audience:      TARGET_AUDIENCE,
    tone:                 TONE_OF_VOICE,
    elevenlabs_voice_id:  ELEVENLABS_VOICE_ID,
    creatomate_template:  CREATOMATE_TEMPLATE_ID,
    drive_folder:         DRIVE_FOLDER_NAME,
    duration_seconds:     VIDEO_DURATION_SECONDS,
    topic,
    platform,
    notes,
    timestamp,
    video_id: videoId
  }
}];

